B.Lk=new A.qr("2026.06.28","\uc624\ub2f5\ub178\ud2b8 \xb7 \ub9c8\uc774\ud398\uc774\uc9c0 \uae30\ub2a5 \uc548\ub0b4","\ud2c0\ub9b0 \ubb38\uc81c\ub97c \uc790\ub3d9\uc73c\ub85c \ubaa8\uc544\ubcf4\ub294 \uc624\ub2f5\ub178\ud2b8\uc640, \ud559\uc2b5 \ud604\ud669\uc744 \ud55c\ub208\uc5d0 \ubcfc \uc218 \uc788\ub294 \ub9c8\uc774\ud398\uc774\uc9c0\uac00 \ucd94\uac00\ub418\uc5c8\uc2b5\ub2c8\ub2e4.",!1)
