B.O1=new A.o3("2026.07.18","\ucd9c\uc81c\ube44\uc911 \uc21c\uc11c\ub300\ub85c \uacf5\ubd80\ud558\ub2c8\uae4c \ud655\uc2e4\ud788 \ud6a8\uc728\uc801\uc774\uc5d0\uc694","\uc5b4\ub5a4 \ucc55\ud130\ubd80\ud130 \ubd10\uc57c\ud560\uc9c0 \ubab0\ub790\ub294\ub370 \ud1b5\uacc4 \uae30\ubc18\uc73c\ub85c \uc21c\uc11c\ub97c \uc7a1\uc544\uc918\uc11c \uc2dc\uac04 \ub0ad\ube44\uac00 \uc904\uc5c8\uc5b4\uc694. \uc720\uc0ac\ubb38\uc81c\ub3c4 \uc2e4\uc81c \uae30\ucd9c\uc774\ub791 \uacb0\uc774 \ube44\uc2b7\ud574\uc11c \ub9cc\uc871\uc2a4\ub7fd\uc2b5\ub2c8\ub2e4.",5,!0)
B.O3=new A.o3("2026.07.12","\uc624\ub2f5\ub178\ud2b8 \uae30\ub2a5\uc774 \uc9c4\uc9dc \ud3b8\ud574\uc694","\ud2c0\ub9b0 \ubb38\uc81c\uac00 \uc790\ub3d9\uc73c\ub85c \ubaa8\uc5ec\uc11c \ub530\ub85c \uc815\ub9ac\ud560 \ud544\uc694\uac00 \uc5c6\uc5b4\uc694. \ubc18\ubcf5\ud574\uc11c \ud2c0\ub9ac\ub294 \uc720\ud615\uc774 \ubb54\uc9c0 \ud55c\ub208\uc5d0 \ubcf4\uc5ec\uc11c \uc88b\uc2b5\ub2c8\ub2e4.",5,!1)
B.O2=new A.o3("2026.07.05","\ub370\uc77c\ub9ac OX\ud034\uc988\ub85c \ub9e4\uc77c \uac10 \uc720\uc9c0\ud558\uae30 \uc88b\uc544\uc694","\ucd9c\ud1f4\uadfc\uae38\uc5d0 \ud558\ub8e8 3\ubb38\uc81c\uc529 \uac00\ubccd\uac8c \ud480 \uc218 \uc788\uc5b4\uc11c \ubd80\ub2f4 \uc5c6\uc774 \ub9e4\uc77c \uacf5\ubd80\ud558\ub294 \uc2b5\uad00\uc774 \uc0dd\uacbc\uc5b4\uc694.",4,!1)
