B.H2=s(["\uac00\uaca9\uc758 \ubd80\ub2f9\ud55c \uacb0\uc815\xb7\uc720\uc9c0\xb7\ubcc0\uacbd","\ucd9c\uace0\uc870\uc808","\uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\ub294 \uc2e0\uaddc \uc9c4\uc785 \ubc29\ud574","\ud1b5\uc0c1\uc801\uc778 \uac70\ub798\uc870\uac74 \uc81c\uc2dc"],t.s)
B.GC=s(['"\ud1b5\uc0c1\uc801\uc778 \uac70\ub798\uc870\uac74 \uc81c\uc2dc"\ub294 \uc0ac\uc5c5\uc790\uac00 \uc2dc\uc7a5\uc5d0\uc11c \ud1b5\uc0c1\uc801\uc73c\ub85c \ud589\ud558\ub294 \uc815\uc0c1\uc801\uc778 \uc601\uc5c5\ud65c\ub3d9\uc5d0 \ud574\ub2f9\ud558\ubbc0\ub85c'],t.s)
